#include <stdio.h>
int main() {
    int T, N, K;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        long long prefixSum[N + 1] = {0};
        for (int i = 0; i < N; i++) {
            prefixSum[i + 1] = prefixSum[i] + A[i];
        }
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                long long sum = prefixSum[j + 1] - prefixSum[i];
                if (sum * 1.0 / (j - i + 1) >= K) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

